<template>
    <div>
      <el-card>
        <el-form label-width="100px" size="mini">
            <el-form-item label="操作类型">
                <el-radio v-model="form.choice" :label="'1'">加钞</el-radio>
                <el-radio v-model="form.choice" :label="'2'">取钞</el-radio>
            </el-form-item>
            <el-form-item label="金额(元)">
                <el-input v-model="form.account"></el-input>
            </el-form-item>
        </el-form>
        <el-form label-width="80px" size="mini">
            <div style="text-align: center;">
                <el-button type="primary" @click="submit">提交</el-button>
            </div>
        </el-form>
      </el-card>

      <el-card v-if="info['余额']">
        <p>操作：{{info['操作']}}</p>
        <p>金额：{{info['金额']}}</p>
        <p>余额：{{info['余额']}}元</p>
        
      </el-card>
        
    </div>
  </template>
  
  <script>
    import {
      adminRecharge, // 存款
  } from '@/api/index'
  
    export default {
      data() {
        return {
            form: {
                account: 0,
                choice: 1
            },
            info: {}
        }
      },
      mounted(){

      },
      methods: {
        // 存款
        async submit(){
            let page = {...this.form}
            if(!page.account){
                this.$message.warning('请输入金额')
                return
            }
            let res = await adminRecharge(page)
            if(res['余额']){
                this.info = res
            }else {
                this.$message.error(res)
            }
        },
      }
    }
  </script>
  
  <style scoped>

    /deep/.el-card{
      margin-top: 10px;
    }
  </style>
  
  


